package com.bankapp.module;

import android.content.Context;
import android.util.Log;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingModule {
    private static final String TAG = "BankingModule";
    private static BankingModule instance;
    private Context context;
    private List<Account> accounts;
    private ExecutorService executor;
    
    private BankingModule(Context context) {
        this.context = context;
        this.accounts = new ArrayList<>();
        this.executor = Executors.newFixedThreadPool(2);
        initializeDefaultAccounts();
    }
    
    public static synchronized BankingModule getInstance(Context context) {
        if (instance == null) {
            instance = new BankingModule(context);
        }
        return instance;
    }
    
    private void initializeDefaultAccounts() {
        accounts.add(new Account("123456789", new BigDecimal("1000.00")));
        accounts.add(new Account("987654321", new BigDecimal("2500.50")));
    }
    
    public BigDecimal getAccountBalance(String accountNumber) {
        for (Account account : accounts) {
            if (account.getAccountNumber().equals(accountNumber)) {
                return account.getBalance();
            }
        }
        return BigDecimal.ZERO;
    }
    
    public boolean processTransaction(String fromAccount, String toAccount, 
                                    BigDecimal amount, String transactionType) {
        if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
            Log.e(TAG, "Invalid transaction amount");
            return false;
        }
        
        return executor.submit(() -> {
            try {
                Account from = findAccount(fromAccount);
                Account to = findAccount(toAccount);
                
                if (from == null || to == null) {
                    Log.e(TAG, "Account not found");
                    return false;
                }
                
                if (transactionType.equals("transfer")) {
                    if (from.getBalance().compareTo(amount) < 0) {
                        Log.e(TAG, "Insufficient funds");
                        return false;
                    }
                    
                    from.setBalance(from.getBalance().subtract(amount));
                    to.setBalance(to.getBalance().add(amount));
                    
                    Log.d(TAG, "Transfer completed: " + amount + " from " + 
                         fromAccount + " to " + toAccount);
                }
                
                return true;
            } catch (Exception e) {
                Log.e(TAG, "Transaction processing error", e);
                return false;
            }
        }).join();
    }
    
    private Account findAccount(String accountNumber) {
        for (Account account : accounts) {
            if (account.getAccountNumber().equals(accountNumber)) {
                return account;
            }
        }
        return null;
    }
    
    public List<Account> getAllAccounts() {
        return new ArrayList<>(accounts);
    }
    
    public void addAccount(String accountNumber, BigDecimal initialBalance) {
        accounts.add(new Account(accountNumber, initialBalance));
    }
    
    public static class Account {
        private String accountNumber;
        private BigDecimal balance;
        
        public Account(String accountNumber, BigDecimal balance) {
            this.accountNumber = accountNumber;
            this.balance = balance != null ? balance : BigDecimal.ZERO;
        }
        
        public String getAccountNumber() {
            return accountNumber;
        }
        
        public BigDecimal getBalance() {
            return balance;
        }
        
        public void setBalance(BigDecimal balance) {
            this.balance = balance.setScale(2, RoundingMode.HALF_UP);
        }
    }
    
    public void shutdown() {
        if (executor != null && !executor.isShutdown()) {
            executor.shutdown();
        }
    }
}